import React from 'react';
import { useEffect } from 'react';
import axios from 'axios';
import AsyncStorage from '@react-native-async-storage/async-storage';

const DebugModule = () => {
  useEffect(() => {
    const logNetworkRequest = (config) => {
      console.debug('NETWORK_REQUEST', config);
      return config;
    };

    const logNetworkResponse = (response) => {
      console.debug('NETWORK_RESPONSE', response.data);
      return response;
    };

    const logAsyncStorageOperation = async (operation, key, value) => {
      if (operation === 'set') {
        try {
          await AsyncStorage.setItem(key, JSON.stringify(value));
          console.log(`ASYNC_STORAGE_SET ${key}:`, value);
        } catch (error) {
          console.error('ASYNC_STORAGE_ERROR', error);
        }
      } else if (operation === 'get') {
        try {
          const storedValue = await AsyncStorage.getItem(key);
          console.log(`ASYNC_STORAGE_GET ${key}:`, JSON.parse(storedValue));
        } catch (error) {
          console.error('ASYNC_STORAGE_ERROR', error);
        }
      }
    };

    const logUserAction = (action, payload) => {
      console.debug('USER_ACTION', action, payload);
    };

    const logStateChange = (componentName, state) => {
      console.log(`STATE_CHANGE ${componentName}:`, state);
    };

    axios.interceptors.request.use(logNetworkRequest);
    axios.interceptors.response.use(logNetworkResponse);

    const originalSetItem = AsyncStorage.setItem;
    AsyncStorage.setItem = async (key, value) => {
      logAsyncStorageOperation('set', key, JSON.parse(value));
      return originalSetItem(key, value);
    };

    const originalGetItem = AsyncStorage.getItem;
    AsyncStorage.getItem = async (key) => {
      await logAsyncStorageOperation('get', key);
      return originalGetItem(key);
    };

    // Example usage
    logUserAction('LOGIN_SUCCESS', { token: 'abc123' });
    logStateChange('UserProfileScreen', { name: 'John Doe', age: 30 });

    return () => {
      axios.interceptors.request.eject(logNetworkRequest);
      axios.interceptors.response.eject(logNetworkResponse);
      AsyncStorage.setItem = originalSetItem;
      AsyncStorage.getItem = originalGetItem;
    };
  }, []);

  return null;
};

export default DebugModule;